using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — strongly-typed metadata access
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2. TryGetTypeInfo<T>() — check-without-throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a source-gen context that only knows about Person.
var restricted = new JsonSerializerOptions { TypeInfoResolver = PersonOnlyContext.Default };

if (restricted.TryGetTypeInfo<Person>(out var personInfo2))
{
    Console.WriteLine($"TryGetTypeInfo<Person> on restricted options: found ({personInfo2!.Type.Name})");
}

if (restricted.TryGetTypeInfo<UnknownType>(out var unknownInfo))
{
    Console.WriteLine($"TryGetTypeInfo<UnknownType>: found");
}
else
{
    Console.WriteLine("TryGetTypeInfo<UnknownType>: not available (no exception thrown)");
}

// Types
public record Person(string Name, int Age);
public record UnknownType(string Data);

// Source-generated context that only resolves Person
[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

